import React, { useEffect, useState } from "react";
import { getDebts } from "../services/debtService";
import "../styles/debt-table.css";

export default function DebtTable({ onDebtSelected }) {
  const [debts, setDebts] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    loadDebts();
  }, []);

  async function loadDebts() {
    try {
      const data = await getDebts(101);
      console.log(data);
      setDebts(data);
    } catch (err) {
      setError("Unable to obtain debt information");
    }
  }

  return (
    <div className="container">
      <h2>Debts</h2>

      <h3>{error && <p>{error}</p>}</h3>

      <table className="debt-table">
        <thead>
          <tr>
            <th>Id</th>
            <th>Customer Id</th>
            <th>Current Balance</th>
            <th>Creditor Name</th>
            <th>Debt Status</th>
          </tr>
        </thead>

        <tbody>
          {debts.map((debt) => (
            <tr
              key={debt.id}
              onClick={() => onDebtSelected(debt.id)}
              style={{ cursor: "pointer" }}
            >
              <td>{debt.id}</td>
              <td>{debt.customerId}</td>
              <td>£{Number(debt.currentBalance).toFixed(2)}</td>
              <td>{debt.creditor}</td>
              <td>{debt.debtStatus}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
